# Tool Name: cwe_347_0_v1_tool
# Description: Decodes a JSON Web Token (JWT) using HS256 algorithm and returns the claims, or an empty dictionary if decoding fails.
# Arguments: token (str) - The JWT token to decode, secret_key (str) - The secret key for verification
# Returns: dict - The decoded claims if successful, empty dictionary if decoding fails
# Requires: PyJWT
def cwe_347_0_v1_tool(token, secret_key):
    """
    Decode a JSON Web Token (JWT) using the HS256 algorithm.

    This function takes a JWT token and a secret key, attempts to decode
    the token using HS256 algorithm, and returns the claims payload.
    If decoding fails for any reason (invalid token, wrong key, etc.),
    it returns an empty dictionary.

    Args:
        token (str): The JWT token to decode
        secret_key (str): The secret key for verification

    Returns:
        dict: The decoded claims if successful, empty dictionary if decoding fails

    Example:
        >>> claims = cwe_347_0_v1_tool("eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...", "my_secret_key")
        >>> print(claims)
        {"sub": "1234567890", "name": "John Doe"}

        >>> claims = cwe_347_0_v1_tool("invalid_token", "wrong_key")
        >>> print(claims)
        {}
    """
    try:
        # Validate input types
        if token is None or not isinstance(token, str):
            return {}

        if secret_key is None or not isinstance(secret_key, str):
            return {}

        if not token or not token.strip():
            return {}

        if not secret_key or not secret_key.strip():
            return {}

        # Import PyJWT library
        import jwt

        # Decode the JWT token with HS256 algorithm
        # options={'verify_signature': True} ensures signature verification
        decoded_payload = jwt.decode(
            token,
            secret_key,
            algorithms=['HS256'],
            options={'require': ['exp', 'iat', 'nbf']}  # Require standard claims
        )

        return decoded_payload

    except jwt.InvalidTokenError:
        # Invalid token format or signature verification failed
        return {}
    except jwt.ExpiredSignatureError:
        # Token has expired
        return {}
    except jwt.InvalidAudienceError:
        # Invalid audience claim
        return {}
    except jwt.InvalidIssuerError:
        # Invalid issuer claim
        return {}
    except jwt.InvalidIssuedAtError:
        # Invalid issued at claim
        return {}
    except jwt.DecodeError:
        # Token decoding failed
        return {}
    except Exception:
        # Any other unexpected error
        return {}


